@import url("https://assets.ohou.se/fonts/pretendard/v1.3.8/pretendardvariable-dynamic-subset.css");

@tailwind base;
@tailwind components;
@tailwind utilities;

@layer base {
  :root {
    --background: #ffffff;
    --foreground: #111827;
    --primary: #111827;
    --primary-foreground: #f9fafb;
    --primary-brand: #00A1FF;
    --primary-brand-weak: #f0f8fc;
    --secondary: #f3f4f6;
    --secondary-foreground: #111827;
    --muted: #f3f4f6;
    --muted-foreground: #6b7280;
    --accent: #f3f4f6;
    --accent-foreground: #111827;
    --destructive: #dc2626;
    --destructive-foreground: #dc2626;
    --destructive-weak: #fef2f2;
    --on-destructive-foreground: #fef2f2;
    --border: #e5e7eb;
    --input: #e5e7eb;
    --ring: #111827;
    --card: #ffffff;
    --card-foreground: #030712;
    --popover: #ffffff;
    --popover-foreground: #030712;
    --inset: #f9fafb;
    --foreground-inverse: #f9fafb;
    --success: #16a34a;
    --success-foreground: #15803d;
    --success-weak: #f0fdf4;
    --warning: #fbbf24;
    --warning-foreground: #b45309;
    --warning-weak: #fffbeb;
    --genuine-blue-50: #F0F8FC;
    --genuine-blue-400: #00A1FF;
    --sidebar: #ffffff;
    --sidebar-foreground: #374151;
    --sidebar-primary: #111827;
    --sidebar-primary-foreground: #f9fafb;
    --sidebar-accent: #f3f4f6;
    --sidebar-accent-foreground: #111827;
    --sidebar-border: #e5e7eb;
    --sidebar-ring: #9ca3af;
  }

  html {
    font-family: "Pretendard Variable", sans-serif;
  }

  * {
    box-sizing: border-box;
    @apply border-border;
  }

  body {
    @apply bg-background text-foreground;
    letter-spacing: -0.3px;
    word-break: keep-all;
    -webkit-font-smoothing: antialiased;
  }
}
